1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const BLOCK_SIZE = 3;
10	const BLOCK_PREMIUM = 60;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	const INSURANCE_VALUE_MULTIPLIER = 10;
24	const insuranceValueFor = (type: string): number => BASE_PREMIUMS[type] * INSURANCE_VALUE_MULTIPLIER;
25	const DEDUCTIBLE = 100;
26	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
27	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
28	const CAP_MULTIPLIER = 2;
29	
30	type Item = { type: string; cursed?: boolean; enchantment?: number };
31	type QuoteStep = { op: "quote"; items: Array<Item> };
32	type Damage = { itemType: string; amount: number };
33	type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Array<Damage> } };
34	type Step = QuoteStep | ClaimStep;
35	type Customer = { yearsWithMHPCO: number };
36	type Scenario = { customer: Customer; steps: Array<Step> };
37	type Policy = { items: Array<Item>; remainingCap: number };
38	
39	const sum = (xs: number[]): number => xs.reduce((a, b) => a + b, 0);
40	
41	const countBy = <T>(items: T[], keyOf: (item: T) => string): Record<string, number> => {
42	  const counts: Record<string, number> = {};
43	  for (const item of items) {
44	    const key = keyOf(item);
45	    counts[key] = (counts[key] ?? 0) + 1;
46	  }
47	  return counts;
48	};
49	
50	const typeOf = (item: Item): string => item.type;
51	const itemTypeOf = (damage: Damage): string => damage.itemType;
52	
53	const qualifiesForBlockDiscount = (type: string, count: number): boolean =>
54	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
55	
56	const subtotalForType = (type: string, count: number): number =>
57	  qualifiesForBlockDiscount(type, count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
58	
59	const policyBaseFor = (items: Item[]): number =>
60	  sum(Object.entries(countBy(items, typeOf)).map(([type, count]) => subtotalForType(type, count)));
61	
62	const hasEnchantmentAtLeast = (item: Item, threshold: number): boolean =>
63	  (item.enchantment ?? 0) >= threshold;
64	
65	const isHighlyEnchanted = (item: Item): boolean =>
66	  hasEnchantmentAtLeast(item, HIGH_ENCHANTMENT_THRESHOLD);
67	
68	const surchargeRate = (item: Item): number =>
69	  (item.cursed ? CURSED_SURCHARGE_RATE : 0) +
70	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
71	
72	const itemSurcharge = (item: Item): number => BASE_PREMIUMS[item.type] * surchargeRate(item);
73	
74	const itemSurchargesFor = (items: Item[]): number => sum(items.map(itemSurcharge));
75	
76	const qualifiesForLoyaltyDiscount = (customer: Customer): boolean =>
77	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
78	
79	const loyaltyDiscountFor = (policyBase: number, customer: Customer): number =>
80	  qualifiesForLoyaltyDiscount(customer) ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
81	
82	const firstInsuranceSurchargeFor = (policyBase: number): number =>
83	  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
84	
85	const isFollowUpQuote = (quoteIndex: number): boolean => quoteIndex > 0;
86	
87	const followUpDiscountFor = (policyBase: number, quoteIndex: number): number =>
88	  isFollowUpQuote(quoteIndex) ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
89	
90	const quotePremium = ({ items }: QuoteStep, customer: Customer, quoteIndex: number): number => {
91	  const policyBase = policyBaseFor(items);
92	  const surcharges = itemSurchargesFor(items) + firstInsuranceSurchargeFor(policyBase);
93	  const discounts = loyaltyDiscountFor(policyBase, customer) + followUpDiscountFor(policyBase, quoteIndex);
94	  return Math.ceil(policyBase + surcharges - discounts + PROCESSING_FEE);
95	};
96	
97	const insuranceSumFor = (items: Item[]): number =>
98	  sum(items.map((item) => insuranceValueFor(item.type)));
99	
100	const payoutRateFor = (item: Item): number =>
101	  hasEnchantmentAtLeast(item, HIGH_ENCHANTMENT_PAYOUT_THRESHOLD) ? HIGH_ENCHANTMENT_PAYOUT_RATE : 1;
102	
103	const insuredItemOfType = (policy: Policy, itemType: string): Item =>
104	  policy.items.find((i) => i.type === itemType)!;
105	
106	const payoutForDamage = (damage: Damage, policy: Policy): number =>
107	  Math.floor(damage.amount * payoutRateFor(insuredItemOfType(policy, damage.itemType)) - DEDUCTIBLE);
108	
109	const validateDamageCounts = (damages: Damage[], policy: Policy): void => {
110	  const damageCounts = countBy(damages, itemTypeOf);
111	  const insuredCounts = countBy(policy.items, typeOf);
112	  for (const [type, count] of Object.entries(damageCounts)) {
113	    if (count > (insuredCounts[type] ?? 0)) {
114	      throw new Error(`Damage count for '${type}' exceeds insured count`);
115	    }
116	  }
117	};
118	
119	const processClaim = (step: ClaimStep, policies: Policy[]): { payout: number; remainingCap: number } => {
120	  const policy = policies[step.policy];
121	  validateDamageCounts(step.incident.damages, policy);
122	  const payout = sum(step.incident.damages.map((d) => payoutForDamage(d, policy)));
123	  policy.remainingCap -= payout;
124	  return { payout, remainingCap: policy.remainingCap };
125	};
126	
127	const capFor = (items: Item[]): number => insuranceSumFor(items) * CAP_MULTIPLIER;
128	
129	const newPolicy = (items: Item[]): Policy =>
130	  ({ items, remainingCap: capFor(items) });
131	
132	const processQuote = (step: QuoteStep, customer: Customer, policies: Policy[]): { premium: number } => {
133	  const premium = quotePremium(step, customer, policies.length);
134	  policies.push(newPolicy(step.items));
135	  return { premium };
136	};
137	
138	export const runScenario = (input: unknown): unknown => {
139	  const scenario = input as Scenario;
140	  const policies: Policy[] = [];
141	  const results = scenario.steps.map((step) =>
142	    step.op === "quote"
143	      ? processQuote(step, scenario.customer, policies)
144	      : processClaim(step, policies)
145	  );
146	  return { results };
147	};
